/**
 * Compute a MetricSummary for the given metric type.
 *
 * Calculates the current value, previous-period value (for trend comparison),
 * and a time-series breakdown based on the query granularity.
 */
private computeMetric(
  type: MetricType,
  orders: Order[],
  users: User[],
  query: AnalyticsQuery,
): MetricSummary {
  const currentValue = this.aggregateMetricValue(type, orders, users);

  // Compute previous-period value by shifting the time range back by its own duration
  const durationMs =
    query.timeRange.end.getTime() - query.timeRange.start.getTime();
  const previousStart = new Date(
    query.timeRange.start.getTime() - durationMs,
  );
  const previousEnd = new Date(query.timeRange.end.getTime() - durationMs);
  const previousOrders = this.orderRepository.findAll(
    (order) =>
      order.createdAt >= previousStart && order.createdAt <= previousEnd,
  );
  const previousUsers = this.userRepository.findAll();
  const previousValue = this.aggregateMetricValue(
    type,
    previousOrders,
    previousUsers,
  );

  // Compute trend
  let changePercent = 0;
  let trend: 'up' | 'down' | 'flat' = 'flat';
  if (previousValue !== 0) {
    changePercent = ((currentValue - previousValue) / previousValue) * 100;
    trend =
      changePercent > 0 ? 'up' : changePercent < 0 ? 'down' : 'flat';
  } else if (currentValue > 0) {
    changePercent = 100;
    trend = 'up';
  }

  return {
    type,
    currentValue,
    previousValue,
    changePercent: Math.round(changePercent * 100) / 100,
    trend,
    timeSeries: this.buildTimeSeries(query, type, orders, users),
  };
}

/**
 * Compute the raw numeric value for a metric type from a set of orders/users.
 */
private aggregateMetricValue(
  type: MetricType,
  orders: Order[],
  _users: User[],
): number {
  switch (type) {
    case 'revenue':
      return orders.reduce((sum, order) => sum + order.total, 0);
    case 'orders':
      return orders.length;
    case 'users': {
      const distinctUserIds = new Set(orders.map((o) => o.userId));
      return distinctUserIds.size;
    }
    case 'conversion': {
      const uniqueUsers = new Set(orders.map((o) => o.userId)).size;
      return uniqueUsers === 0
        ? 0
        : Math.round((orders.length / uniqueUsers) * 100) / 100;
    }
  }
}

