/**
 * Build time-series data points for the query's time range and granularity.
 *
 * Divides the time range into buckets based on granularity, aggregates the
 * metric value within each bucket, and generates human-readable labels.
 */
private buildTimeSeries(
  query: AnalyticsQuery,
  type: MetricType,
  orders: Order[],
  users: User[],
): TimeSeriesPoint[] {
  const buckets = this.generateBucketBoundaries(
    query.timeRange.start,
    query.timeRange.end,
    query.granularity,
  );
  const points: TimeSeriesPoint[] = [];

  for (let i = 0; i < buckets.length - 1; i++) {
    const bucketStart = buckets[i];
    const bucketEnd = buckets[i + 1];
    const bucketOrders = orders.filter(
      (o) => o.createdAt >= bucketStart && o.createdAt < bucketEnd,
    );
    const value = this.aggregateMetricValue(type, bucketOrders, users);
    points.push({
      timestamp: bucketStart,
      value,
      label: this.formatBucketLabel(bucketStart, query.granularity),
    });
  }

  return points;
}

/**
 * Generate bucket boundary timestamps from start to end using the given granularity.
 * Returns an array of timestamps where each adjacent pair defines one bucket [start, end).
 */
private generateBucketBoundaries(
  start: Date,
  end: Date,
  granularity: import('../models/analytics.js').TimeGranularity,
): Date[] {
  const boundaries: Date[] = [];
  let current = new Date(start);

  while (current < end) {
    boundaries.push(new Date(current));
    switch (granularity) {
      case 'hour':
        current = new Date(current.getTime() + 60 * 60 * 1000);
        break;
      case 'day':
        current = new Date(current.getTime() + 24 * 60 * 60 * 1000);
        break;
      case 'week':
        current = new Date(current.getTime() + 7 * 24 * 60 * 60 * 1000);
        break;
      case 'month': {
        const next = new Date(current);
        next.setMonth(next.getMonth() + 1);
        current = next;
        break;
      }
    }
  }
  // Add the end boundary
  boundaries.push(new Date(end));
  return boundaries;
}

/**
 * Format a bucket start timestamp into a human-readable label.
 */
private formatBucketLabel(
  date: Date,
  granularity: import('../models/analytics.js').TimeGranularity,
): string {
  const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const months = [
    'Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun',
    'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec',
  ];
  switch (granularity) {
    case 'hour':
      return `${date.getHours().toString().padStart(2, '0')}:00`;
    case 'day':
      return `${days[date.getDay()]} ${date.getDate()}`;
    case 'week':
      return `${months[date.getMonth()]} ${date.getDate()}`;
    case 'month':
      return `${months[date.getMonth()]} ${date.getFullYear()}`;
  }
}

