/**
 * Compute the breakdown of orders by status.
 * Groups orders by status, counts each group, and calculates percentages.
 */
private computeOrderStatusBreakdown(
  orders: Order[],
): OrderStatusBreakdown[] {
  const total = orders.length;
  if (total === 0) return [];

  const counts = new Map<Order['status'], number>();
  for (const order of orders) {
    counts.set(order.status, (counts.get(order.status) ?? 0) + 1);
  }

  const breakdown: OrderStatusBreakdown[] = [];
  for (const [status, count] of counts) {
    breakdown.push({
      status,
      count,
      percentage: Math.round((count / total) * 10000) / 100,
    });
  }

  // Sort by count descending for consistent output
  breakdown.sort((a, b) => b.count - a.count);
  return breakdown;
}

