/**
 * Compute the top users ranked by total revenue.
 * Groups orders by userId, sums revenue, joins with user names,
 * sorts descending by revenue, and slices to the requested limit.
 */
private computeTopUsers(
  orders: Order[],
  users: User[],
  limit: number,
): TopUser[] {
  // Group orders by userId
  const userStats = new Map<
    string,
    { orderCount: number; totalRevenue: number }
  >();
  for (const order of orders) {
    const stats = userStats.get(order.userId) ?? {
      orderCount: 0,
      totalRevenue: 0,
    };
    stats.orderCount++;
    stats.totalRevenue += order.total;
    userStats.set(order.userId, stats);
  }

  // Build a lookup for user names
  const userNameMap = new Map<string, string>();
  for (const user of users) {
    userNameMap.set(user.id, user.name);
  }

  // Build TopUser array, sort by revenue descending, and limit
  const topUsers: TopUser[] = [];
  for (const [userId, stats] of userStats) {
    topUsers.push({
      userId,
      userName: userNameMap.get(userId) ?? 'Unknown',
      orderCount: stats.orderCount,
      totalRevenue: Math.round(stats.totalRevenue * 100) / 100,
    });
  }

  topUsers.sort((a, b) => b.totalRevenue - a.totalRevenue);
  return topUsers.slice(0, limit);
}

